import{_ as l,C as s,o as e,c as n,a2 as a,b as r,w as o,a as h,E as d,a3 as c}from"./chunks/framework.ByZGvHP2.js";const w=JSON.parse('{"title":"Multi-Host Management","description":"","frontmatter":{},"headers":[],"relativePath":"guide/multi-host.md","filePath":"guide/multi-host.md"}'),u={name:"guide/multi-host.md"};function m(p,t,g,A,f,k){const i=s("Mermaid");return e(),n("div",null,[t[1]||(t[1]=a('<h1 id="multi-host-management" tabindex="-1">Multi-Host Management <a class="header-anchor" href="#multi-host-management" aria-label="Permalink to &quot;Multi-Host Management&quot;">​</a></h1><p>Alpaka Desktop seamlessly connects to multiple Ollama instances simultaneously. This feature is designed for power users and enterprise teams who need to route workloads between local hardware, dedicated LAN servers, and Ollama Cloud.</p><div class="spotlight-card p-4 my-6"><div class="spotlight-content flex items-start gap-3"><div class="mt-1 text-brand"><svg width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg></div><div><h4 class="font-medium text-text-1 m-0">Why use Multi-Host?</h4><p class="text-sm text-text-2 mt-1 mb-0">Offload heavy reasoning models (like DeepSeek-R1) to a dedicated GPU server while running smaller, faster models (like Llama 3) on your local machine for zero-latency tasks.</p></div></div></div><h2 id="architecture-data-flow" tabindex="-1">Architecture &amp; Data Flow <a class="header-anchor" href="#architecture-data-flow" aria-label="Permalink to &quot;Architecture &amp; Data Flow&quot;">​</a></h2><p>When switching hosts, Alpaka routes inference requests to the active host without requiring an application restart. Your chat history, drafts, and system prompts remain unified locally.</p>',5)),(e(),r(c,null,{default:o(()=>[d(i,{id:"mermaid-13",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5BAlpaka%20Desktop%5D%20--%3E%7CSettings%20DB%7C%20B%7BHost%20Router%7D%0A%20%20%20%20%0A%20%20%20%20B%20--%3E%7Chttp%3A%2F%2Flocalhost%3A11434%7C%20C%5BLocal%20Machine%5D%0A%20%20%20%20B%20--%3E%7Chttp%3A%2F%2F192.168.1.50%3A11434%7C%20D%5BLAN%20GPU%20Server%5D%0A%20%20%20%20B%20--%3E%7Chttps%3A%2F%2Fapi.ollama.com%7C%20E%5BOllama%20Cloud%5D%0A%20%20%20%20%0A%20%20%20%20C%20--%3E%20F((Llama%203))%0A%20%20%20%20D%20--%3E%20G((DeepSeek%20R1))%0A%20%20%20%20E%20--%3E%20H((Ollama%20API))%0A%20%20%20%20%0A%20%20%20%20classDef%20default%20fill%3A%23111111%2Cstroke%3A%23333333%2Ccolor%3A%23EEEEEE%0A%20%20%20%20classDef%20router%20fill%3A%232a1a4a%2Cstroke%3A%238251EE%2Ccolor%3A%23EEEEEE%0A%20%20%20%20class%20B%20router%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[h(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<h2 id="adding-a-host" tabindex="-1">Adding a Host <a class="header-anchor" href="#adding-a-host" aria-label="Permalink to &quot;Adding a Host&quot;">​</a></h2><p>To connect a new Ollama instance to your workspace:</p><ol><li>Navigate to <strong>Settings → Hosts</strong> (or use the keyboard shortcut <code>Ctrl+H</code>).</li><li>Click the <strong>Add host</strong> button.</li><li>Enter the target endpoint URL: <ul><li>For LAN servers: <code>http://192.168.x.x:11434</code></li><li>For Ollama Cloud: <code>https://api.ollama.com</code></li></ul></li><li>Click <strong>Save</strong>.</li></ol><p><em>Alpaka Desktop will immediately dispatch a ping to verify connectivity and establish a health baseline.</em></p><h2 id="health-monitoring" tabindex="-1">Health Monitoring <a class="header-anchor" href="#health-monitoring" aria-label="Permalink to &quot;Health Monitoring&quot;">​</a></h2><p>Alpaka runs a background telemetry loop that continuously monitors the health of all configured hosts. Status indicators are displayed globally in the top navigation bar:</p><ul><li>🟢 <strong>Online:</strong> The host is reachable. Network latency is displayed in milliseconds.</li><li>🔴 <strong>Offline:</strong> The host failed to respond or connection timed out.</li><li>⚪ <strong>Unknown:</strong> The host has not yet been pinged by the telemetry loop.</li></ul><h2 id="instant-host-switching" tabindex="-1">Instant Host Switching <a class="header-anchor" href="#instant-host-switching" aria-label="Permalink to &quot;Instant Host Switching&quot;">​</a></h2><p>To switch the active inference endpoint:</p><ol><li>Click the <strong>Host Indicator</strong> in the top navigation bar to reveal the quick-switcher dropdown.</li><li>Select your desired host.</li></ol><p>Upon selection, the Model Manager immediately syncs with the newly active host, reloading the available model registry. Your active conversations remain intact and accessible.</p><h2 id="authenticating-with-ollama-cloud" tabindex="-1">Authenticating with Ollama Cloud <a class="header-anchor" href="#authenticating-with-ollama-cloud" aria-label="Permalink to &quot;Authenticating with Ollama Cloud&quot;">​</a></h2><p>When <code>https://api.ollama.com</code> is configured as a host, Alpaka automatically elevates its security context.</p><p>API keys stored in <strong>Settings → Account → API Keys</strong> (which are securely managed via your OS Keyring) are seamlessly injected as Bearer tokens on all outbound requests to this specific host. Local hosts remain unaffected by this authentication layer.</p>',14))])}const v=l(u,[["render",m]]);export{w as __pageData,v as default};
